{"path": "/tmp/sv-58ca4090a96140ab9d7b57960f9d38dd/Components/Pages/Catalog/CatalogPagination.razor", "file_text": "<nav class="catalog-pagination" aria-label="Product pagination">
    <button class="page-btn"
            disabled="@(CurrentPage <= 1)"
            @onclick="@(() => GoToPage(CurrentPage - 1))">
        Previous
    </button>

    @for (int i = 1; i <= TotalPages; i++)
    {
        var page = i;
        <button class="page-btn @(page == CurrentPage ? "active" : "")"
                @onclick="@(() => GoToPage(page))">
            @page
        </button>
    }

    <button class="page-btn"
            disabled="@(CurrentPage >= TotalPages)"
            @onclick="@(() => GoToPage(CurrentPage + 1))">
        Next
    </button>
</nav>

@code {
    [Parameter] public int CurrentPage { get; set; } = 1;
    [Parameter] public int TotalPages { get; set; } = 1;
    [Parameter] public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != CurrentPage)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }
}
"}

