.catalog-filters {
    background: #fafafa;
    padding: 1.5rem;
    border-radius: 8px;
    border: 1px solid #e5e7eb;
}

.catalog-filters h2 {
    margin: 0 0 1rem 0;
    font-size: 1.2rem;
    color: #333;
}

.filter-section {
    margin-bottom: 1.25rem;
}

.filter-section h3 {
    margin: 0 0 0.5rem 0;
    font-size: 0.9rem;
    font-weight: 600;
    color: #555;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.filter-empty {
    color: #999;
    font-size: 0.85rem;
    margin: 0;
}

.filter-checkbox {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.25rem 0;
    cursor: pointer;
    font-size: 0.9rem;
}

.filter-checkbox input[type="checkbox"] {
    cursor: pointer;
}

.price-inputs {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.price-inputs label {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
    font-size: 0.85rem;
    color: #555;
}

.price-inputs input {
    padding: 0.4rem 0.5rem;
    border: 1px solid #d1d5db;
    border-radius: 4px;
    font-size: 0.9rem;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    margin-top: 1rem;
}

.btn-apply {
    padding: 0.6rem 1rem;
    background: #2563eb;
    color: #fff;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    font-weight: 600;
}

.btn-apply:hover {
    background: #1d4ed8;
}

.btn-clear {
    padding: 0.6rem 1rem;
