toolArgs.file_text:
.catalog-layout {
    display: flex;
    gap: 2rem;
    align-items: flex-start;
}

.catalog-layout > :first-child {
    flex: 0 0 25%;
    min-width: 220px;
}

.catalog-main {
    flex: 1;
    min-width: 0;
}

.catalog-loading,
.catalog-empty,
.catalog-error {
    text-align: center;
    padding: 3rem 1rem;
    color: #666;
}

.catalog-error {
    color: #dc2626;
    background: #fef2f2;
    border: 1px solid #fecaca;
    border-radius: 8px;
}

.catalog-error button {
    margin-top: 0.75rem;
    padding: 0.5rem 1rem;
    background: #2563eb;
    color: #fff;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    font-weight: 600;
}

.catalog-error button:hover {
    background: #1d4ed8;
}

